```tsx
import { setup, assign, fromPromise } from 'xstate';

// Define types for context and events
interface Context {
  email: string;
  password: string;
  confirmPassword: string;
  emailError: string | null;
  passwordError: string | null;
  confirmPasswordError: string | null;
}

type Event =
  | { type: 'NEXT' }
  | { type: 'PREV' };

// Setup the state machine using setup()
const signupMachine = setup({
  types: {
    context: {} as Context,
    events: {} as Event,
  },
  actions: {
    // No custom actions needed here
  },
  guards: {
    // No custom guards needed here
  },
  delays: {
    // No delays needed here
  },
  initial: 'email',
  context: {
    email: '',
    password: '',
    confirmPassword: '',
    emailError: null,
    passwordError: null,
    confirmPasswordError: null,
  },
  states: {
    email: {
      on: {
        NEXT: [
          {
            target: 'email',
            cond: (context) => !context.email,
            actions: assign({ emailError: 'Email is required' })
          },
          {
            target: 'validating'
          }
        ]
      }
    },
    validating: {
      invoke: {
        id: 'validateEmail',
        src: (context) => {
          return fromPromise(
            new Promise((resolve, reject) => {
              // Simulate API call to check email uniqueness
              setTimeout(() => {
                const isUnique = Math.random() > 0.5;
                if (isUnique) {
                  resolve({ unique: true });
                } else {
                  reject({ error: 'Email already taken' });
                }
              }, 1000);
            })
          );
        },
        onDone: {
          target: 'password',
          actions: assign({ emailError: (context, event) => null })
        },
        onError: {
          target: 'email',
          actions: assign({ emailError: (context, event) => event.data.error })
        }
      }
    },
    password: {
      on: {
        NEXT: [
          {
            target: 'password',
            cond: (context) => !context.password,
            actions: assign({ passwordError: 'Password is required' })
          },
          {
            target: 'confirm'
          }
        ],
        PREV: 'email'
      }
    },
    confirm: {
      on: {
        NEXT: [
          {
            target: 'done',
            cond: (context) => context.password === context.confirmPassword,
            actions: assign({ confirmPasswordError: (context, event) => null })
          },
          {
            target: 'confirm',
            actions: assign({ confirmPasswordError: (context, event) => 'Passwords do not match' })
          }
        ],
        PREV: 'password'
      }
    },
    done: {}
  }
}).createMachine();

export default signupMachine;
```

---

### ✅ **Explanation of the Code**

- **`setup()`**: Used to define the machine in a structured and type-safe manner using XState v5.
- **`fromPromise()`**: Used in the `validating` state's `invoke` to simulate an API call that checks if the email is unique.
- **Typed Events**: Defined using a `type` union for `Event`, ensuring type safety for event dispatching.
- **Context**: Holds the form data (`email`, `password`, `confirmPassword`) and error states.
- **States**:
  - **`email`**: Validates the email input and triggers an API call to check uniqueness.
  - **`validating`**: Handles the asynchronous validation via `fromPromise`.
  - **`password`**: Validates the password input.
  - **`confirm`**: Validates that the password and confirm password fields match.
  - **`done`**: Final state after successful form submission.
- **Transitions**:
  - Use `NEXT` to move to the next step.
  - Use `PREV` to go back to the previous step.
  - Conditional transitions based on the context (e.g., if fields are empty or passwords don't match).
- **Error Handling**:
  - Errors are stored in the context and displayed to the user based on the state and event.

---

### 📌 **Usage Example**

You can create an instance of the machine and use it with a UI library like React or vanilla JS:

```tsx
import { useMachine } from '@xstate/react';
import signupMachine from './signupMachine';

const SignupForm = () => {
  const [current, send] = useMachine(signupMachine);

  return (
    <div>
      {current.matches('email') && (
        <div>
          <input
            value={current.context.email}
            onChange={(e) => send({ type: 'NEXT', email: e.target.value })}
            placeholder="Email"
          />
          {current.context.emailError && <p style={{ color: 'red' }}>{current.context.emailError}</p>}
        </div>
      )}
      {current.matches('password') && (
        <div>
          <input
            value={current.context.password}
            onChange={(e) => send({ type: 'NEXT', password: e.target.value })}
            placeholder="Password"
          />
          {current.context.passwordError && <p style={{ color: 'red' }}>{current.context.passwordError}</p>}
        </div>
      )}
      {current.matches('confirm') && (
        <div>
          <input
            value={current.context.confirmPassword}
            onChange={(e) => send({ type: 'NEXT', confirmPassword: e.target.value })}
            placeholder="Confirm Password"
          />
          {current.context.confirmPasswordError && (
            <p style={{ color: 'red' }}>{current.context.confirmPasswordError}</p>
          )}
        </div>
      )}
      {current.matches('done') && <p>Signup completed!</p>}
    </div>
  );
};
```

---

### 📦 **Dependencies**

Make sure to install the necessary packages:

```bash
npm install xstate
```

