### 🧩 Projector Function

```javascript
function project(state, event) {
  switch (event.type) {
    case 'ItemAdded':
      return {
        ...state,
        itemCount: state.itemCount + event.data.quantity,
        totalCents: state.totalCents + event.data.quantity * event.data.priceCents
      };

    case 'ItemRemoved':
      return {
        ...state,
        itemCount: state.itemCount - event.data.quantity,
        totalCents: state.totalCents - event.data.quantity * event.data.priceCents
      };

    case 'QuantityUpdated':
      const { oldQuantity, newQuantity, priceCents } = event.data;
      const delta = newQuantity - oldQuantity;
      return {
        ...state,
        itemCount: state.itemCount + delta,
        totalCents: state.totalCents + delta * priceCents
      };

    case 'CartCleared':
      return {
        ...state,
        itemCount: 0,
        totalCents: 0
      };

    default:
      // Ignore unknown events
      return state;
  }
}
```

