// And `uploadFile(file): Observable<Progress>` is the function that handles the upload.
const files$ = /* your source of files */;

files$
  .pipe(
    mergeMap(file => uploadFile(file), 3) // <-- Concurrency is capped at 3
  )
  .subscribe(progress => {
    // Handle progress updates from each upload
    console.log('Upload progress:', progress);
  });
```

